import React, { useState } from 'react';
import { Home, BarChart2, Layers, Settings, LogOut, ChevronLeft } from 'lucide-react';

const Sidebar = () => {
  const [isCollapsed, setIsCollapsed] = useState(false);

  const toggleSidebar = () => {
    setIsCollapsed(!isCollapsed);
  };

  const menuItems = [
    { icon: Home, label: 'Dashboard' },
    { icon: BarChart2, label: 'Analytics' },
    { icon: Layers, label: 'Reports' },
    { icon: Settings, label: 'Settings' },
  ];

  return (
    <aside className={`relative bg-zinc-900/70 border-r border-zinc-800 transition-all duration-300 ${isCollapsed ? 'w-16' : 'w-64'} overflow-hidden`}>
      <button
        onClick={toggleSidebar}
        className="absolute top-1/2 -right-3 -translate-y-1/2 bg-indigo-500 text-white rounded-full p-2 shadow-lg hover:bg-indigo-600 focus:outline-none focus:ring-2 focus:ring-indigo-500/50"
      >
        <ChevronLeft className={`h-5 w-5 transition-transform duration-300 ${isCollapsed ? 'rotate-180' : ''}`} />
      </button>
      <div className="px-4 py-6 flex flex-col h-full">
        <div className="flex items-center justify-center mb-8">
          <h2 className={`text-xl font-bold text-indigo-400 font-heading transition-opacity duration-300 ${isCollapsed ? 'opacity-0' : 'opacity-100'}`}>
            InsightFlow
          </h2>
        </div>
        <nav className="flex-1">
          <ul>
            {menuItems.map((item, index) => (
              <li key={index} className="mb-2">
                <a
                  href="#"
                  className={`flex items-center space-x-3 p-3 rounded-lg hover:bg-zinc-700/50 transition-colors duration-200 group ${isCollapsed ? 'justify-center' : ''}`}
                >
                  <item.icon className="h-5 w-5 text-zinc-400 group-hover:text-indigo-300" />
                  {!isCollapsed && (
                    <span className="text-zinc-300 group-hover:text-indigo-300 transition-colors duration-200">{item.label}</span>
                  )}
                </a>
              </li>
            ))}
          </ul>
        </nav>
        <div className="mt-auto">
          <a
            href="#"
            className={`flex items-center space-x-3 p-3 rounded-lg hover:bg-zinc-700/50 transition-colors duration-200 group ${isCollapsed ? 'justify-center' : ''}`}
          >
            <LogOut className="h-5 w-5 text-zinc-400 group-hover:text-red-400" />
            {!isCollapsed && (
              <span className="text-zinc-300 group-hover:text-red-400 transition-colors duration-200">Logout</span>
            )}
          </a>
        </div>
      </div>
    </aside>
  );
};

export default Sidebar;

