import React, { useState } from 'react';
import { TrendingUp, TrendingDown, DollarSign, Users } from 'lucide-react';

const StatCard = ({ title, value, percentage, icon: Icon, color }) => {
  const isPositive = percentage >= 0;
  return (
    <div className="bg-zinc-900/60 border border-zinc-800 rounded-xl xl p-6 shadow-card-inner transition-all duration-300 hover:scale-[1.02] hover:shadow-xl">
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-lg font-semibold text-zinc-300">{title}</h3>
        <Icon className={`h-6 w-6 text-${color}-400`} />
      </div>
      <div className="text-3xl sm:text-4xl font-bold text-zinc-100 mb-2">{value}</div>
      <div className={`flex items-center space-x-2 text-sm font-medium ${isPositive ? `text-${color}-400` : 'text-red-400'}`}>
        <span>{percentage >= 0 ? '+' : ''}{percentage}%</span>
        {isPositive ? <TrendingUp className="h-4 w-4" /> : <TrendingDown className="h-4 w-4" />}
        <span>vs last period</span>
      </div>
    </div>
  );
};

const DataCardGrid = () => {
  const cardData = [
    { title: 'Total Revenue', value: '$1.2M', percentage: 15.2, icon: DollarSign, color: 'indigo' },
    { title: 'New Customers', value: '5,430', percentage: 8.5, icon: Users, color: 'emerald' },
    { title: 'Conversion Rate', value: '3.8%', percentage: -1.1, icon: TrendingUp, color: 'amber' },
    { title: 'Average Order Value', value: '$150', percentage: 4.9, icon: DollarSign, color: 'blue' },
  ];

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mt-10">
      {cardData.map((card, index) => (
        <StatCard
          key={index}
          title={card.title}
          value={card.value}
          percentage={card.percentage}
          icon={card.icon}
          color={card.color}
        />
      ))}
    </div>
  );
};

export default DataCardGrid;

