import React, { useState } from 'react';
import { Search, Filter } from 'lucide-react';

const transactions = [
  { id: 1, date: '2023-10-26', description: 'Online Store Purchase', amount: '-$150.00', status: 'Completed' },
  { id: 2, date: '2023-10-25', description: 'Subscription Renewal', amount: '-$29.99', status: 'Pending' },
  { id: 3, date: '2023-10-25', description: 'Freelance Payment', amount: '+$500.00', status: 'Completed' },
  { id: 4, date: '2023-10-24', description: 'Cloud Service Fee', amount: '-$99.50', status: 'Failed' },
  { id: 5, date: '2023-10-24', description: 'Gift Card Purchase', amount: '-$75.00', status: 'Completed' },
  { id: 6, date: '2023-10-23', description: 'Referral Bonus', amount: '+$25.00', status: 'Completed' },
  { id: 7, date: '2023-10-23', description: 'Software License', amount: '-$199.00', status: 'Completed' },
  { id: 8, date: '2023-10-22', description: 'Refund Processed', amount: '+$50.00', status: 'Completed' },
];

const statusClasses = {
  Completed: 'bg-emerald-500/20 text-emerald-400',
  Pending: 'bg-amber-500/20 text-amber-400',
  Failed: 'bg-red-500/20 text-red-400',
};

const TransactionTable = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState('All');

  const filteredTransactions = transactions.filter((transaction) =>
    (filterStatus === 'All' || transaction.status === filterStatus) &&
    (transaction.description.toLowerCase().includes(searchTerm.toLowerCase()) ||
     transaction.amount.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  return (
    <div className="mt-16 bg-zinc-900/60 border border-zinc-800 rounded-xl xl p-6 shadow-card-inner">
      <div className="flex flex-col sm:flex-row items-center justify-between mb-6 space-y-4 sm:space-y-0">
        <h3 className="text-xl font-semibold text-zinc-200">Recent Transactions</h3>
        <div className="flex items-center space-x-4 w-full sm:w-auto">
          <div className="relative flex-1 sm:flex-1">
            <input
              type="text"
              placeholder="Search transactions..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="bg-zinc-800/50 border border-zinc-700 rounded-lg xl px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500/50 text-zinc-300 placeholder-zinc-500 w-full"
            />
            <Search className="h-4 w-4 absolute right-3 top-1/2 -translate-y-1/2 text-zinc-400" />
          </div>
          <select
            value={filterStatus}
            onChange={(e) => setFilterStatus(e.target.value)}
            className="bg-zinc-800/50 border border-zinc-700 rounded-lg xl px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500/50 text-zinc-300 appearance-none"
          >
            <option value="All">All Status</option>
            <option value="Completed">Completed</option>
            <option value="Pending">Pending</option>
            <option value="Failed">Failed</option>
          </select>
        </div>
      </div>
      <div className="overflow-x-auto">
        <table className="min-w-full divide-y divide-zinc-800">
          <thead className="bg-zinc-800/50">
            <tr>
              <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-zinc-400 uppercase tracking-wider">Date</th>
              <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-zinc-400 uppercase tracking-wider">Description</th>
              <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-zinc-400 uppercase tracking-wider">Amount</th>
              <th scope="col" className="px-6 py-3 text-center text-xs font-medium text-zinc-400 uppercase tracking-wider">Status</th>
            </tr>
          </thead>
          <tbody className="bg-zinc-900/50 divide-y divide-zinc-800">
            {filteredTransactions.map((transaction) => (
              <tr key={transaction.id} className="hover:bg-zinc-800/30 transition-colors duration-200">
                <td className="px-6 py-4 whitespace-nowrap text-sm text-zinc-300">{transaction.date}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-zinc-200">{transaction.description}</td>
                <td className={`px-6 py-4 whitespace-nowrap text-right text-sm font-semibold ${transaction.amount.startsWith('+') ? 'text-emerald-400' : 'text-red-400'}`}>
                  {transaction.amount}
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-center">
                  <span className={`px-3 py-1 rounded-full text-xs font-medium ${statusClasses[transaction.status]}`}>
                    {transaction.status}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default TransactionTable;

